"""
Tiling module for efficient and easy tiling point clouds for different formats.
"""

from abc import ABC, abstractmethod
from collections import defaultdict
from copy import deepcopy
from typing import (
    Iterator,
    Tuple,
    List,
    Optional,
    NamedTuple,
    Iterable,
    DefaultDict,
    Set,
    Mapping,
)

import numpy as np
import numpy.typing as npt
from geosat.tools.boundingboxes import BoundingBox

from geosat.cloud import PointCloud
from geosat.cloud.pyvoxels import cube_window


class TilingException(Exception):
    """When an error is detected during tiling process"""


TileCoord = Tuple[int, int]
"""The coordinates of a 2D tile"""
PointIndices = npt.NDArray[np.int64]
"""A 1D numpy array of integers that designates point indices"""
Coords2D = npt.NDArray[np.float64]
"""A numpy array of float coordinates of shape ``(n, 2)`` where each row designates
the coordinates of a 2D point
"""
TileCoords2D = npt.NDArray[np.int64]
"""A numpy array of integers of shape ``(n, 2)`` where each row designates 
the coordinates of a 2D tile
"""


class Tile(NamedTuple):
    """
    Class to handle output of tiling process.

    :param coord: The coordinate of the tile.
    :param indices: Corresponding indices from the original coordinates of the
        original point cloud (before tiling) which are within the tile.
    :param inners_count: The number of points within the inner area (i.e. the
        tile without its padding area). If set to None, then this information
        is unknown hence there are no preconception about the sorting of `indices`
        However, if set to N, then we implicitly have to sort the `indices` making
        the first N indices corresponding to the inner area.
    """

    coord: TileCoord
    indices: PointIndices
    inners_count: Optional[int] = None


class Tiler(ABC):
    """An interface which describes methods to group 2D float coordinates
    into clusters, called tiles, that share a common 2D integer coordinate (grid)
    """

    @abstractmethod
    def generate_tiles(self, coords: Coords2D) -> Iterator[Tile]:
        """Compute for each input 2D float coordinates the tile it falls into

        :param coords: an array of 2D float coordinates
        :return: An iterator of :class:`Tile` objects
        """

    @abstractmethod
    def compute_extent(self, tile_coord: TileCoord) -> BoundingBox:
        """Compute the axis-aligned rectangular extent of the tile located at the
        provided tile coordinate. If a 2D float coordinates falls into a given tile,
        it is guaranteed to also fall into its extent.

        .. warning::
            The inverse might not be true for some ``Tiler`` implementations

        :param tile_coord: The coordinates of the tile for which the extent must be
            calculated
        :return: The extent of the corresponding tile
        """


def _extract_indices_by_tile_coords(
    tile_coords: TileCoords2D,
) -> DefaultDict[TileCoord, npt.NDArray[np.int64]]:
    """
    :param tile_coords: The 2D tile coordinates to sort
    :return: A dictionary that contains the unique input 2D tile coordinates as keys,
        and the indices of the tiles with these coordinates in the input array as values

    An inefficient equivalent with lists instead of numpy arrays could look like:

    >>> def _simple_extract_indices_by_tile_coords(
    ...     _tile_coords: TileCoords2D,
    ... ) -> DefaultDict[TileCoord, List[int]]:
    ...     mapping = defaultdict(list)
    ...     for i, (x, y) in enumerate(_tile_coords):
    ...         mapping[(int(x), int(y))].append(i)
    ...     return mapping
    >>>
    >>> coords = np.array([[0, 0], [1, 0], [0, 0]])
    >>> mapping_ = _simple_extract_indices_by_tile_coords(coords)
    >>> mapping_
    defaultdict(<class 'list'>, {(0, 0): [0, 2], (1, 0): [1]})
    >>> fast_mapping = {
    ...     tile_coord: list(indices)
    ...     for tile_coord, indices in _extract_indices_by_tile_coords(coords).items()
    ... }
    >>> assert fast_mapping == mapping_
    """
    sorted_indices = np.lexsort(tile_coords.T)
    sorted_coords = tile_coords[sorted_indices]
    # Detecting changes between consecutive coordinates by subtracting:
    diffs = np.diff(sorted_coords, axis=0)
    split_indices = np.flatnonzero(diffs.any(axis=1)) + 1
    parts = np.split(sorted_indices, split_indices) if len(sorted_indices) else []
    return defaultdict(
        lambda: np.arange(0),
        {
            (int(tile_coords[part[0]][0]), int(tile_coords[part[0]][1])): part
            for part in parts
        },
    )


class RectangularPaddedTiler(Tiler):
    """
    :param origin: The 2D float position of the ``(0, 0)`` :class:`TileCoord`
    :param resolution: The un-padded width and length of generated tiles
    :param padding: The additional distance each tile should be dilated on each side
    :param generate_near_tiles: If set to True, the tiles that only contain padded data are also generated

    Retrieve all the tiles given float coordinates falls into:

    >>> tiler = RectangularPaddedTiler(
    ...     origin=(0., 0.),
    ...     resolution=(10., 10.),
    ...     padding=(2., 2.),
    ...     generate_near_tiles=False
    ... )
    >>> coords = np.array([[0.0, 0.0]])
    >>> sorted(tile.coord for tile in tiler.generate_tiles(coords))
    [(0, 0)]
    >>> tiler.generate_near_tiles = True
    >>> sorted(tile.coord for tile in tiler.generate_tiles(coords))
    [(-1, -1), (-1, 0), (0, -1), (0, 0)]

    Compute the extent of a given tile:

    >>> tiler = RectangularPaddedTiler(
    ...     origin=(0., 0.),
    ...     resolution=(10., 10.),
    ...     padding=(1., 1.),
    ...     generate_near_tiles=True
    ... )
    >>> tiler.compute_extent((0, 0))
    <BoundingBox(xmin: -1.0, ymin: -1.0, xmax: 11.0, ymax: 11.0)>
    >>> tiler.compute_extent((1, 1))
    <BoundingBox(xmin: 9.0, ymin: 9.0, xmax: 21.0, ymax: 21.0)>
    >>> tiler = RectangularPaddedTiler(
    ...     origin=(10.0, 10.0),
    ...     resolution=(10., 10.),
    ...     padding=(1., 1.),
    ...     generate_near_tiles=True
    ... )
    >>> tiler.compute_extent((0, 0))
    <BoundingBox(xmin: 9.0, ymin: 9.0, xmax: 21.0, ymax: 21.0)>
    """

    def __init__(
        self,
        origin: Tuple[float, float],
        resolution: Tuple[float, float],
        padding: Tuple[float, float] = (0.0, 0.0),
        generate_near_tiles: bool = False,
    ) -> None:
        if np.greater(padding, resolution).any():
            raise ValueError(
                f"The padding cannot be superior to the resolution. "
                f"Found a padding of {padding} and a resolution of {resolution}"
            )
        self.origin = origin
        self.resolution = resolution
        self.padding = padding
        self.generate_near_tiles = generate_near_tiles

    def compute_tile_coords(self, coords: Coords2D) -> TileCoords2D:
        """Converts 2D float coordinates to the tile coordinates they fall into,
        without taking into account the padding.

        :param coords: An array of 2D float coordinates
        :return: Their corresponding 2D tile coordinates
        """
        return np.floor(
            np.subtract(np.asarray(coords).reshape(-1, 2), self.origin)
            / self.resolution
        ).astype(int)

    def compute_extent(self, tile_coord: TileCoord) -> BoundingBox:
        minimum = np.multiply(tile_coord, self.resolution) - self.padding + self.origin
        maximum = (
            np.multiply(np.add(tile_coord, 1), self.resolution)
            + self.padding
            + self.origin
        )
        return BoundingBox(*minimum, *maximum)

    @staticmethod
    def get_near_tiles(tile_coord: TileCoord) -> TileCoords2D:
        return cube_window(tile_coord)

    def _are_in_padding(
        self, tile_coord: TileCoord, coords: Coords2D
    ) -> npt.NDArray[np.bool_]:
        tile_position = np.add(np.multiply(tile_coord, self.resolution), self.origin)
        pad_mins = np.subtract(tile_position, self.padding)
        pad_maxs = np.add(tile_position, np.add(self.padding, self.resolution))
        tile_maxs = np.add(tile_position, self.resolution)
        within_padded_extent = np.logical_and(
            np.all(pad_mins <= coords, axis=1), np.all(coords < pad_maxs, axis=1)
        )
        within_inner_extent = np.logical_and(
            np.all(tile_position <= coords, axis=1), np.all(coords < tile_maxs, axis=1)
        )
        return np.logical_and(within_padded_extent, np.logical_not(within_inner_extent))

    def _are_in_tile(
        self, tile_coord: TileCoord, coords: Coords2D
    ) -> npt.NDArray[np.bool_]:
        tile_position = np.add(np.multiply(tile_coord, self.resolution), self.origin)
        mins = np.subtract(tile_position, self.padding)
        maxes = np.add(tile_position, np.add(self.padding, self.resolution))
        return np.logical_and(
            np.all(mins <= coords, axis=1), np.all(coords < maxes, axis=1)
        )

    def _get_selected_indices(
        self,
        indices_by_tile_coords: Mapping[TileCoord, npt.NDArray[np.int64]],
        tile_coord: TileCoord,
    ) -> PointIndices:
        selected_tiles: List[TileCoord] = [
            tile_coord,
            *(  # type: ignore[misc]
                (x, y)  # type: ignore[has-type]
                for x, y in self.get_near_tiles(tile_coord)
            ),
        ]
        indices_lists = [
            indices_by_tile_coords[selected_tile] for selected_tile in selected_tiles
        ]
        selected_indices = np.concatenate(indices_lists)
        return selected_indices

    def _get_included_indices(
        self,
        coords: Coords2D,
        tile_coord: TileCoord,
        indices_by_tile_coords: Mapping[TileCoord, npt.NDArray[np.int64]],
    ) -> PointIndices:
        """
        Does not make the difference between inner indices and indices from padding.
        """
        selected_indices = self._get_selected_indices(
            indices_by_tile_coords, tile_coord
        )
        selected_coords = coords[selected_indices]
        return selected_indices[self._are_in_tile(tile_coord, selected_coords)]

    def _get_padded_indices(
        self,
        coords: Coords2D,
        tile_coord: TileCoord,
        indices_by_tile_coords: Mapping[TileCoord, npt.NDArray[np.int64]],
    ) -> PointIndices:
        selected_indices = self._get_selected_indices(
            indices_by_tile_coords, tile_coord
        )
        selected_coords = coords[selected_indices]
        return selected_indices[self._are_in_padding(tile_coord, selected_coords)]

    def _generate_tile_coords_to_test(
        self, tile_coords: Iterable[TileCoord]
    ) -> List[TileCoord]:
        tile_coords_to_test = list(tile_coords)
        if self.padding != (0, 0) and self.generate_near_tiles:
            near_tile_coords: Set[TileCoord] = {  # type: ignore[misc]
                (int(tile_x), int(tile_y))  # type: ignore[has-type]
                for tile_coord in tile_coords_to_test
                for tile_x, tile_y in self.get_near_tiles(tile_coord)
            }
            near_tile_coords.difference_update(tile_coords_to_test)
            tile_coords_to_test.extend(near_tile_coords)
        return tile_coords_to_test

    def generate_tiles(
        self, coords: Coords2D, inners_at_beginning: bool = False
    ) -> Iterator[Tile]:
        tile_coords = self.compute_tile_coords(coords)
        indices_by_tile_coords = _extract_indices_by_tile_coords(tile_coords)
        tiles_coords_to_test: List[TileCoord] = self._generate_tile_coords_to_test(
            indices_by_tile_coords
        )
        for tile_coord in tiles_coords_to_test:
            inners_count: Optional[int] = None
            if self.padding != (0, 0):
                if inners_at_beginning:
                    padded_indices = self._get_padded_indices(
                        coords, tile_coord, indices_by_tile_coords
                    )
                    inner_indices = indices_by_tile_coords[tile_coord]
                    indices: PointIndices = np.concatenate(
                        (inner_indices, padded_indices)
                    )
                    inners_count = len(inner_indices)
                else:
                    indices = self._get_included_indices(
                        coords, tile_coord, indices_by_tile_coords
                    )
            else:  # Optimization when there is no padding
                indices = indices_by_tile_coords[tile_coord]
            if len(indices):
                yield Tile(tile_coord, indices, inners_count)


class PaddedTiler(RectangularPaddedTiler):
    """A tiler with square padded tiles

    :param origin: The 2D float position of the bottom left corner of the tile
        of :class:`TileCoord` ``(0, 0)``
    :param resolution: The un-padded side length of the generated tiles
    :param padding: The additional distance each tile should be dilated on each side
    """

    def __init__(
        self, origin: Tuple[float, float], resolution: float, padding: float = 0.0
    ) -> None:
        super().__init__(origin, (resolution, resolution), (padding, padding))


def get_cloud_inners_count(cloud: PointCloud) -> int:
    return cloud.metadata["geosat"]["inners"]


def _yield_cloud_with_inners_count(
    cloud: PointCloud, indices: Tile
) -> Iterable[PointCloud]:
    inners = indices.inners_count
    if inners is None:
        yield cloud[indices.indices]
    else:
        tile_cloud: PointCloud = deepcopy(cloud[indices.indices])
        tile_cloud.metadata.setdefault("geosat", {})["inners"] = inners
        yield tile_cloud


def split_cloud(
    cloud: PointCloud,
    size: float,
    padding: float = 0.0,
    inners_at_beginning: bool = False,
) -> Iterator[PointCloud]:
    """
    Split a point cloud in tiles of side size less or equal than resolution
    if no padding is set. If a padding is provided, each sub-cloud will have
    a side length lesser or equal to ``resolution + 2 * padding``.

    :param cloud: original point cloud
    :param size: size of tiles before applying padding
    :param padding: distance to add to each border to generate tiles
    :param inners_at_beginning: if set to true the inner points of the tile will be
        stored at the beginning of the point list. **WARNING: This increases the
        of the tiling by 45%.**
    """
    x, y, _z = cloud.bb_min()
    tiler = PaddedTiler((x, y), size, padding)
    tiles = tiler.generate_tiles(cloud.coords[:, :2], inners_at_beginning)
    for tile in tiles:
        if inners_at_beginning:
            yield from _yield_cloud_with_inners_count(cloud, tile)
        else:
            yield cloud[tile.indices]


def split_cloud_in_rectangles(
    cloud: PointCloud,
    size: Tuple[float, float],
    origin: Optional[Tuple[float, float]] = None,
    padding: Tuple[float, float] = (0, 0),
    inners_at_beginning: bool = False,
) -> Iterator[PointCloud]:
    """
    Split a point cloud in tiles of side size less or equal than resolution if no
    padding is set. If a padding is provided, each sub-cloud will have a side
    length lesser or equal to ``resolution + 2 * padding``.

    :param cloud: original point cloud
    :param size: size of tiles before applying padding
    :param origin:
    :param padding: distance to add to each border to generate tiles
    :param inners_at_beginning: if set to true the inner points of the tile will be
        stored at the beginning of the point list. **WARNING: This increases the
        of the tiling by 45%.**
    """
    if origin is None:
        x, y, _z = cloud.bb_min()
        origin = x, y
    tiler = RectangularPaddedTiler(origin, size, padding)
    tiles = tiler.generate_tiles(cloud.coords[:, :2], inners_at_beginning)
    for tile in tiles:
        if inners_at_beginning:
            yield from _yield_cloud_with_inners_count(cloud, tile)
        else:
            yield cloud[tile.indices]


def split_cloud_with_overlap(
    cloud: PointCloud,
    size: float,
    overlap_ratio: float,
    inners_at_beginning: bool = False,
) -> Iterator[PointCloud]:
    """
    Split a cloud with ``size`` and each tile having at least ``overlap_ratio`` %
    of overlap with other tiles.

    :param cloud: cloud to be tiled
    :param size: size of each tile in cloud CRS
    :param overlap_ratio: Value in range ``(0, 1(`` corresponding to the minimum
        overlap ratio between tiles
    :param inners_at_beginning: if set to true the inner points of the tile will be
        stored at the beginning of the point list. **WARNING: This increases the
        of the tiling by 45%.**
    """
    if overlap_ratio >= 1:
        raise TilingException(
            "Overlap ratio value can not be greater than 100%! "
            f"(currently {overlap_ratio})"
        )
    padding = overlap_ratio * size / 2
    size *= 1 - overlap_ratio
    yield from split_cloud(cloud, size, padding, inners_at_beginning)
